class Trie:
    def __init__(self):
        self.root = {}
    def insert(self, word):
        node = self.root
        for ch in word:
            if ch not in node:
                node[ch] = {}
            node = node[ch]
        node['$'] = True
    def delete(self, prefix):
        def dfs(node, prefix):
            if prefix in node:
                del node[prefix]
                return
            for ch,p in node.items():
                dfs(p, prefix+ch)
            if not node:
                del node['$']
        dfs(self.root, prefix)
        return True

def main():
    trie = Trie()
    while True:
        line = input()
        if line == '':
            break
        words = line.split()
        if words[0] == 'insert':
            word = words[1]
            trie.insert(word)
        elif words[0] == 'delete':
            prefix = words[1]
            trie.delete(prefix)
    print(list(trie.root.keys()))
if __name__ == '__main__':
    main()

