    bool insert(string word){
        node = root;
        for (char ch: word) {
            if (!node[ch])
                node[ch] = new TrieNode;
            node = node[ch];
        }
        node['$'] = new TrieNode;
    }
    bool delete(string prefix) {
        def dfs(node, prefix) {
            if (prefix in node) {
                deleteNode(node, prefix);
                return;
            }
            for (auto& p: node) {
                dfs(p.second, prefix + p.first);
            }
            if (node.size() == 1 && !node['$'])
                deleteNode(node, '');
        }
        dfs(root, prefix);
        return true;
